printf(
			'<div id="qm-php-nope" class="notice notice-error is-dismissible"><p>%s</p></div>',
			wp_kses(
				sprintf(
					/* translators: 1: Query Monitor, 2: Required PHP version number, 3: Current PHP version number, 4: URL of PHP update help page */
					__( 'The %1$s plugin requires PHP version %2$s or higher. This site is running PHP version %3$s. <a href="%4$s">Learn about updating PHP</a>.', 'query-monitor' ),
					'Query Monitor',
					self::$minimum_version,
					PHP_VERSION,
					'https://wordpress.org/support/update-php/'
				),
				array(
					'a' => array(
						'href' => array(),
					),
				)
			)
		)

printf(
			// phpcs:ignore WordPress.WP.EnqueuedResources.NonEnqueuedStylesheet
			'<link rel="stylesheet" href="%1$s?ver=%2$s" media="all" />',
			esc_url( QueryMonitor::init()->plugin_url( 'assets/build/toolbar.css' ) ),
			esc_attr( QM_VERSION )
		)

array_map( function( $value ) {
					$type = gettype( $value );

					switch ( $type ) {
						case 'object':
							return get_class( $value );
						case 'boolean':
							return $value ? 'true' : 'false';
						case 'integer':
						case 'double':
							return $value;
						case 'string':
							if ( strlen( $value ) > 50 ) {
								return "'" . substr( $value, 0, 20 ) . '...' . substr( $value, -20 ) . "'";
							}
							return "'" . $value . "'";
					}

					return $type;
				}, $frame['args'] ?? array() )

printf(
				/* translators: %s: Plugin or theme name */
				esc_html__( 'This message was triggered by %s.', 'query-monitor' ),
				'<b>' . esc_html( $name ) . '</b>'
			)

printf(
								/* translators: %s: Action name */
								esc_html__( 'Warning: The %s action is extremely resource intensive. Try to avoid using it.', 'query-monitor' ),
								'<code>all</code>'
							)

preg_replace( '#\s?([^0-9,\.]+)#', '<small>$1</small>', sprintf(
			/* translators: %s: Memory usage in megabytes with a decimal fraction. Note the space between value and unit symbol. */
			esc_html__( '%s MB', 'query-monitor' ),
			$memory
		) )

array_filter( array_map( function( $type ) use ( $data ) {
			return $data->types[ $type ] ?? 0;
		}, array_keys( $types ) ) )

